    public void AddSession()
    {
        Session session = new Session();

        session.Id = this.idCounter++;

        session.Permissions = new List<string> { "Create", "Delete" };

        session.Preferences = new Preferences { Age = 21, Name = "<NAME>" };

        BinaryFormatter formatter = new BinaryFormatter();

        using (FileStream stream = File.OpenWrite("sessions.bin"))
